import React from "react";
import { useParams } from "react-router-dom";

import Input from "../../shared/components/FormElements/Input";
import Button from "../../shared/components/FormElements/Button";
import { VALIDATOR_REQUIRE, VALIDATOR_MINLENGTH } from "../../shared/components/util/validators";
import { useForm } from "../../shared/components/hooks/form-hook";

import './PlaceForm.css';

const DUMMY_PLACES = [
    {
    id: "p1",
    title: "Dubai – Stad van records en glitter",
    description: "One of the most famous sky scrapers in the world!",
    imageUrl:
      "https://travelizi.nl/sites/default/files/inline-images/Atlantis%2C%20The%20Palm%2C%20Dubai-faisal-manga-4NeuZU-ynnw-unsplash.jpg",
    address: "Midtown Manhattan, Fifth Avenue at 34th Street, New York City.",
    location: {
      lat: 40.7484405,
      lng: -73.9878584
    },
    creator: "u1"
  },
  {
    id: "p2",
    title: "New York City (Statue of Liberty)",
    description:
      "There are different geographical, cultural, financial, and political aspects to consider.",
    imageUrl:
      "https://www.westernunion.com/blogs-staticassets/R25-07.05.0-161/media/Travel_Spotlight_USA_02.jpg",
    location: {
      lat: 40.6892494,
      lng: 74.0470753
    },
    creator: "u2"
  },

  { 
    id: 'p3', 
    title: ' Canda(Moraine Lake)',
     description: 'Moraine Lake is a snow and glacially fed alpine lake in Banff National Park, 14 kilometres outside the village of Lake Louise, Alberta, Canada. ',
      imageUrl: 'https://banfflakelouise.bynder.com/m/3d04f19979f432ec/2000x1080_jpg-2022_MoraineLake_TravelAlberta_RothandRamberg-3.jpg',
       location: { 
        lat: 51.3215507, 
        lng: -116.1952415, 
    }, 
       creator: 'u3' 
    },

{
     id: 'p4',
      title: ' India( jaipur,hawa Mahal)',
       description: 'The Hawa Mahal is a palace in the city of Jaipur, Rajasthan, India. Built from red and pink sandstone, it is on the edge of the City Palace, Jaipur. ', 
       imageUrl: 'https://www.tourmyindia.com/images/hawa-mahal-fort-jaipur.jpg',
        location: { 
            lat: 26.9240458, 
            lng: 75.8267144, }, 
            creator: 'u4' 
        },
        { 
            id: 'p5',
             title: ' Africa( Pyramids of Giza)',
              description: 'Perhaps the most iconic ancient landmarks in Africa, the Pyramids of Giza are also among the greatest mysteries on the planet. ',
               imageUrl: 'https://dailypassport.com/wp-content/uploads/sites/8/2023/07/1-DP-Ancient-Landmarks-Africa.jpg?resize=1024,768',
                location: { 
                    lat: 29.9772962, 
                    lng: 31.1299206, },
                     creator: 'u5'
                    
                    },
];

const UpdatePlace = () => {
  const { placeId } = useParams();

  const identifiedPlace = DUMMY_PLACES.find(p => p.id === placeId);

  const [formState, inputHandler] = useForm(
    {
      title: {
        value: identifiedPlace ? identifiedPlace.title : "",
        isValid: !!identifiedPlace
      },
      description: {
        value: identifiedPlace ? identifiedPlace.description : "",
        isValid: !!identifiedPlace
      }
    },
    !!identifiedPlace
  );

  if (!identifiedPlace) {
    return (
      <div className="center">
        <h2>Could not find place!</h2>
      </div>
    );
  }

  return (
    <form className="place-form">
      <Input
        id="title"
        element="input"
        type="text"
        label="Title"
        validators={[VALIDATOR_REQUIRE]}
        errorText="Please enter a valid title."
        onInput={inputHandler}
        initialValue={formState.inputs.title.value}
        initialValid={formState.inputs.title.isValid}
      />

      <Input
        id="description"
        element="textarea"
        label="Description"
        validators={[VALIDATOR_MINLENGTH(5)]}
        errorText="Please enter a valid description (at least 5 characters)."
        onInput={inputHandler}
        initialValue={formState.inputs.description.value}
        initialValid={formState.inputs.description.isValid}
      />

      <Button type="submit" disabled={!formState.isValid}>
        Update PLACE
      </Button>
    </form>
  );
};
